    TreeNode right;
}

class Pair {
    TreeNode node;
    int depth;
}

public Pair findLCAUtil(TreeNode root) {
    if (root == null) {
        return new Pair(null, 0);
    }

    Pair leftLCA = findLCAUtil(root.left);
    Pair rightLCA = findLCAUtil(root.right);

